	m.HandleFunc("POST "+options.BaseURL+"/v1/funding-sources", wrapper.CreateFundingSource)
	m.HandleFunc("GET "+options.BaseURL+"/v1/health", wrapper.GetHealth)
	m.HandleFunc("GET "+options.BaseURL+"/v1/intents", wrapper.ListIntents)
	m.HandleFunc("POST "+options.BaseURL+"/v1/intents", wrapper.CreateIntent)
